import React, { useState, useEffect } from 'react';
import fishData from './FishData.json';
import { Row, Col, Card, Button, Form, InputGroup } from 'react-bootstrap';

export default function KnowledgePage() {
    const [fishes, setFishes] = useState([]);
    const [expandedFishIds, setExpandedFishIds] = useState([]);
    const [searchQuery, setSearchQuery] = useState('');

    useEffect(() => {
        setFishes(fishData.freshwater_fish_vietnam);
    }, []);

    const toggleFishInfo = (id) => {
        setExpandedFishIds((prev) =>
            prev.includes(id) ? prev.filter((fid) => fid !== id) : [...prev, id]
        );
    };

    // Filter fishes based on search query
    const filteredFishes = fishes.filter(fish => 
        fish.name.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <div className="container main-content">
            <h1 className="text-center text-primary mb-4">
                Kiến thức về các loài cá nước ngọt Việt Nam
            </h1>

            {/* Search Bar */}
            <div className="mb-4">
                <InputGroup className="shadow-sm">
                    <InputGroup.Text id="search-addon" className="bg-primary text-white">
                        <i className="bi bi-search"></i>
                    </InputGroup.Text>
                    <Form.Control
                        placeholder="Tìm kiếm theo tên cá..."
                        aria-label="Search"
                        aria-describedby="search-addon"
                        value={searchQuery}
                        onChange={(e) => setSearchQuery(e.target.value)}
                        className="py-2"
                    />
                    {searchQuery && (
                        <Button 
                            variant="outline-secondary" 
                            onClick={() => setSearchQuery('')}
                        >
                            <i className="bi bi-x-lg"></i>
                        </Button>
                    )}
                </InputGroup>
                {filteredFishes.length === 0 && searchQuery && (
                    <div className="text-center text-muted mt-2">
                        Không tìm thấy cá nào với tên "{searchQuery}"
                    </div>
                )}
                <div className="text-end text-muted mt-2">
                    Hiển thị {filteredFishes.length} / {fishes.length} loài cá
                </div>
            </div>

            <Row>
                {filteredFishes.map((fish) => {
                    const isExpanded = expandedFishIds.includes(fish.id);
                    return (
                        <Col key={fish.id} xs={12} sm={6} md={4} lg={3}>
                            <Card className="mb-4 shadow-sm">
                                {!isExpanded ? (
                                    <>
                                        <Card.Img
                                            variant="top"
                                            src={fish.image_url}
                                            alt={fish.name}
                                            onError={(e) => {
                                                e.target.onerror = null;
                                                e.target.src = '/images/not-found.jpg';
                                            }}
                                            style={{ height: '200px', objectFit: 'cover' }}
                                        />
                                        <Card.Body className="text-center">
                                            <Card.Title>
                                                {searchQuery ? (
                                                    <>
                                                        {fish.name.split(new RegExp(`(${searchQuery})`, 'i')).map((part, i) => 
                                                            part.toLowerCase() === searchQuery.toLowerCase() ? 
                                                                <span key={i} className="bg-warning">{part}</span> : 
                                                                <span key={i}>{part}</span>
                                                        )}
                                                    </>
                                                ) : (
                                                    fish.name
                                                )}
                                            </Card.Title>
                                        </Card.Body>
                                    </>
                                ) : (
                                    <Card.Body>
                                        <Card.Title>
                                            {searchQuery ? (
                                                <>
                                                    {fish.name.split(new RegExp(`(${searchQuery})`, 'i')).map((part, i) => 
                                                        part.toLowerCase() === searchQuery.toLowerCase() ? 
                                                            <span key={i} className="bg-warning">{part}</span> : 
                                                            <span key={i}>{part}</span>
                                                    )}
                                                </>
                                            ) : (
                                                fish.name
                                            )}
                                        </Card.Title>
                                        <Card.Text>
                                            <strong>Đặc điểm:</strong> {fish.characteristics.appearance}
                                            <br />
                                            <strong>Kích cỡ:</strong> {fish.characteristics.size}
                                            <br />
                                            <strong>Tập tính:</strong> {fish.behavior}
                                            <br />
                                            <strong>Mồi yêu thích:</strong> {fish.favorite_bait}
                                            <br />
                                            <strong>Thông tin:</strong> {fish.info}
                                        </Card.Text>
                                    </Card.Body>
                                )}
                                <Card.Footer className="text-center">
                                    <Button variant="info" onClick={() => toggleFishInfo(fish.id)}>
                                        Infor
                                    </Button>
                                </Card.Footer>
                            </Card>
                        </Col>
                    );
                })}
            </Row>
        </div>
    );
}
